function serveSitemapIndex() {
  const dt = new Date().toISOString().slice(0,10);
  const sidoList = Object.keys(REGIONS).map(s => SIDO_EN[s]||s);
  const sitemapEntries = [
    `<sitemap><loc>https://allpaystore.com/sitemap-static.xml</loc><lastmod>${dt}</lastmod></sitemap>`,
    ...sidoList.map(se => `<sitemap><loc>https://allpaystore.com/sitemap-${se}.xml</loc><lastmod>${dt}</lastmod></sitemap>`)
  ].join('');
  return new Response(`<?xml version="1.0" encoding="UTF-8"?><sitemapindex xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">${sitemapEntries}</sitemapindex>`,
    { headers: {'Content-Type':'application/xml;charset=UTF-8','Cache-Control':'public,max-age=3600'} });
}

function serveSitemapByKey(key) {
  const dt = new Date().toISOString().slice(0,10);
  const PROD_KEYS = Object.values(SUBJECTS).map(v=>v.en);
  const urls = [];
  if (key === 'static') {
    urls.push(`<url><loc>https://allpaystore.com/</loc><changefreq>daily</changefreq><priority>1.0</priority><lastmod>${dt}</lastmod></url>`);
    urls.push(`<url><loc>https://allpaystore.com/contact</loc><changefreq>monthly</changefreq><priority>0.5</priority></url>`);
    Object.keys(REGIONS).forEach(rk => {
      const se = SIDO_EN[rk]||rk;
      urls.push(`<url><loc>https://allpaystore.com/${se}</loc><changefreq>weekly</changefreq><priority>0.9</priority><lastmod>${dt}</lastmod></url>`);
    });
    return new Response(`<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">${urls.join('')}</urlset>`,
      { headers: {'Content-Type':'application/xml;charset=UTF-8','Cache-Control':'public,max-age=3600'} });
  }
  for (const [rk, reg] of Object.entries(REGIONS)) {
    const se = SIDO_EN[rk]||rk;
    if (se !== key) continue;
    for (const [ak, area] of Object.entries(reg.areas)) {
      const ge = DISTRICT_EN[ak]||ak;
      urls.push(`<url><loc>https://allpaystore.com/${se}/${ge}</loc><changefreq>weekly</changefreq><priority>0.8</priority><lastmod>${dt}</lastmod></url>`);
      for (const dong of (area.dongs||[])) {
        const dr = toRoman(dong);
        urls.push(`<url><loc>https://allpaystore.com/${se}/${ge}/${dr}</loc><changefreq>weekly</changefreq><priority>0.7</priority><lastmod>${dt}</lastmod></url>`);
        for (const pk of PROD_KEYS) {
          urls.push(`<url><loc>https://allpaystore.com/${se}/${ge}/${dr}/${pk}</loc><changefreq>monthly</changefreq><priority>0.6</priority><lastmod>${dt}</lastmod></url>`);
        }
      }
    }
    return new Response(`<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">${urls.join('')}</urlset>`,
      { headers: {'Content-Type':'application/xml;charset=UTF-8','Cache-Control':'public,max-age=3600'} });
  }
  return null;
}

function serveSitemapChunk(n) {
  return Response.redirect('https://allpaystore.com/sitemap.xml', 301);
}


