// ── 라우터 ────────────────────────────────────────────────



export default {
  async fetch(request) {
    const url = new URL(request.url);
    const path = decodeURIComponent(url.pathname);
    const parts = path.split('/').filter(Boolean);
    const h = { 'Content-Type': 'text/html;charset=UTF-8', 'Cache-Control': 'public,max-age=3600' };

    // ── 문의 API ──────────────────────────────────────────
    if (path === '/api/contact' && request.method === 'POST') {
      const corsHeaders = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
      try {
        const body = await request.json();
        const { name, grade, phone, address, message } = body;
        if (!name || !grade || !phone || !address) {
          return new Response(JSON.stringify({ ok: false, error: '필수 항목 누락' }), { headers: corsHeaders });
        }
        const GAS_URL = 'https://script.google.com/macros/s/AKfycbz3FYy6m02GJZHmVFuinxZov4W_QYGmXzftq_Q43Z-KwXklWPvu1Y23dUcHdsa2itKG/exec';
        const gasRes = await fetch(GAS_URL, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ name, grade, phone, address, message }) });
        const gasData = await gasRes.json();
        if (gasData.ok) return new Response(JSON.stringify({ ok: true }), { headers: corsHeaders });
        return new Response(JSON.stringify({ ok: false, error: gasData.error }), { headers: corsHeaders });
      } catch (e) {
        return new Response(JSON.stringify({ ok: false, error: e.message }), { headers: corsHeaders });
      }
    }

    // ── 정적 ──────────────────────────────────────────────
    if (path === '/sitemap.xml') return serveSitemapIndex();
    const sitemapMatch = path.match(/^\/sitemap-([a-z0-9_-]+)\.xml$/);
    if (sitemapMatch) { const r = serveSitemapByKey(sitemapMatch[1]); if (r) return r; }
    if (path.match(/^\/sitemap\d+\.xml$/)) return serveSitemapChunk(0);
    if (path === '/rss.xml' || path === '/feed' || path === '/feed.xml') return serveRSS();
    if (path === '/contact') return new Response(makeContactPage(), { headers: h });
    if (path === '/favicon.ico' || path === '/favicon-32.png' || path === '/favicon-16.png') {
      const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 32 32"><rect width="32" height="32" rx="8" fill="#0D2E6E"/><rect x="4" y="9" width="24" height="14" rx="2" stroke="white" stroke-width="2" fill="none"/><path d="M4 14h24M9 19h6" stroke="white" stroke-width="1.5" stroke-linecap="round"/></svg>`;
      return new Response(svg, { headers: { 'Content-Type': 'image/svg+xml', 'Cache-Control': 'public,max-age=86400' } });
    }
    if (path === '/robots.txt') return new Response('User-agent: *\nAllow: /\nSitemap: https://allpaystore.com/sitemap.xml', { headers: { 'Content-Type': 'text/plain' } });

    // ── 홈 ────────────────────────────────────────────────
    if (parts.length === 0) return new Response(makeHomePage(), { headers: h });

    // ── 4단계: /{sido}/{gu}/{dong}/{product} ──────────────
    if (parts.length === 4) {
      const dongName = fromRoman(parts[0], parts[1], parts[2]);
      if (dongName) {
        const page = makeDongPageByName(parts[0], parts[1], dongName, parts[3], null);
        if (page) return new Response(page, { headers: h });
      }
    }

    // ── 3단계: /{sido}/{gu}/{dong} ────────────────────────
    if (parts.length === 3) {
      const dongName = fromRoman(parts[0], parts[1], parts[2]);
      if (dongName) {
        const page = makeDongMainPage(parts[0], parts[1], dongName);
        if (page) return new Response(page, { headers: h });
      }
    }

    // ── 2단계: /{sido}/{gu} ───────────────────────────────
    if (parts.length === 2) {
      const kr = toKr(parts[0], parts[1], null, null, null);
      const page = makeAreaPage(kr.sido, kr.district);
      if (page) return new Response(page, { headers: h });
    }

    // ── 1단계: /{sido} ────────────────────────────────────
    if (parts.length === 1) {
      const kr = toKr(parts[0], null, null, null, null);
      const page = makeSidoPage(kr.sido);
      if (page) return new Response(page, { headers: h });
    }

    // ── 404 ───────────────────────────────────────────────
    return new Response(`<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"><title>404 - 올페이스토어</title></head><body><h1>페이지를 찾을 수 없습니다</h1><a href="/">홈으로</a></body></html>`,
      { status: 404, headers: { 'Content-Type': 'text/html;charset=UTF-8' } });
  }
};
